{{ja-pron|やな|acc=1|acc_ref=<ref name="KDJ2Oyana">{{R:Nihon Kokugo Daijiten 2 Online|やな 【梁・簗】|lid=20020438d5efsZPhW77q|kotobank=梁・簗}}</br>
